// LBS 蒙皮公式
// finalPos = sum( w[i] * (boneWorld[i] * invBindMatrix[i]) * restPos )
//
// 其中:
//   w[i]       = 第 i 根骨骼的权重
//   boneWorld[i] = 第 i 根骨骼当前帧的世界矩阵
//   invBindMatrix[i] = 第 i 根骨骼的逆绑定矩阵
//   restPos    = 顶点在绑定姿态下的初始位置
//
// skinMatrix[i] = boneWorld[i] * invBindMatrix[i]
// finalPos = sum( w[i] * skinMatrix[i] * restPos )
//
// 对于最多 4 根骨骼影响的顶点:
// finalPos = w0*M0*restPos + w1*M1*restPos + w2*M2*restPos + w3*M3*restPos

// WGSL GPU 蒙皮着色器
struct SkinningUniforms {
  jointMatrices: array<mat4x4<f32>, 128>,  // 骨骼矩阵数组
}
@group(0) @binding(0) var<uniform> skinning: SkinningUniforms;

struct VertexInput {
  @location(0) position: vec3<f32>,
  @location(1) normal: vec3<f32>,
  @location(2) joints: vec4<u32>,      // 4 个骨骼索引
  @location(3) weights: vec4<f32>,     // 4 个权重
};

@vertex
fn vs_main(in: VertexInput) -> VertexOutput {
  // 加权求和蒙皮矩阵
  let skinMatrix =
    skinning.jointMatrices[in.joints.x] * in.weights.x +
    skinning.jointMatrices[in.joints.y] * in.weights.y +
    skinning.jointMatrices[in.joints.z] * in.weights.z +
    skinning.jointMatrices[in.joints.w] * in.weights.w;

  // 应用蒙皮变换
  let skinnedPos = skinMatrix * vec4<f32>(in.position, 1.0);
  let skinnedNormal = (skinMatrix * vec4<f32>(in.normal, 0.0)).xyz;

  // 继续 MVP 变换...
  return camera.viewProjection * skinnedPos;
}

// 使用纹理存储骨骼矩阵
@group(0) @binding(1) var jointTexture: texture_2d<f32>;

fn getJointMatrix(jointIndex: u32) -> mat4x4<f32> {
  let col0 = textureLoad(jointTexture, vec2<u32>(jointIndex * 4u + 0u, frameIndex), 0);
  let col1 = textureLoad(jointTexture, vec2<u32>(jointIndex * 4u + 1u, frameIndex), 0);
  let col2 = textureLoad(jointTexture, vec2<u32>(jointIndex * 4u + 2u, frameIndex), 0);
  let col3 = textureLoad(jointTexture, vec2<u32>(jointIndex * 4u + 3u, frameIndex), 0);
  return mat4x4<f32>(col0, col1, col2, col3);
}
